:- use_module(library(http/thread_httpd)). :- use_module(library(http/http_dispatch)). :- use_module(library(http/http_cors)). :- use_module(library(http/http_json)). :- set_setting(http:cors, [*]). :- http_handler(root(test), handle_test, [methods([post, options])]). handle_test(Request) :- option(method(options), Request), !, cors_enable(Request, [methods([post, options])]), format('~n'). handle_test(Request) :- cors_enable, http_read_json_dict(Request, Dict), reply_json_dict(_{echo: Dict.msg}). :- initialization(main, main). main :- http_server(http_dispatch, [port(8099)]), thread_get_message(_).